public class Matrix {
    public static void main(String[] args) {
        int[][] m = new int[3][3];
        for (int i = 0; i < 3; i++)
            for (int j = 0; j < 3; j++)
                m[i][j] = i * 3 + j;
        System.out.println(m[0][0] + " " + m[1][1] + " " + m[2][2]);
        System.out.println(m[2][0] + " " + m[0][2]);
    }
}
